+            FcpError::InvalidRequest { code, message } => {
+                assert_eq!(code, 1003);
+                assert!(
+                    message.contains("api.bitbucket.org") || message.contains("bitbucket.org"),
+                    "rejection should name the policy host: {message}"
+                );
+            }
